I've completed a thorough exploration of the qsvo implementation across the sw-cor24-apl C interpreter. Here's the full flow and architecture:

---

## 1. TOKENIZATION (tok.h - lines 171-178)

The tokenizer identifies the `qsvo` keyword as a distinct token type:

```c
#define TOK_QSVO   14   // qsvo — shared variable offer (□SVO)

// Detection in tokenize() function:
len = str_match(line, i, "qsvo");
if (len == 4 && !is_alnum(line[i + 4])) {
    tok_type[t] = TOK_QSVO;
    tok_pos[t] = i;
    tok_val[t] = 0;
    t++;
    i = i + 4;
    continue;
}
```

**String Literal Support** (tok.h, lines 205-216):
The tokenizer also supports single-quoted string literals for qsvo names (`'MMIO' qsvo 242`):
```c
if (line[i] == 39) {  // single quote
    tok_type[t] = TOK_STRING;
    tok_pos[t] = i;
    tok_val[t] = i;  // store start of string content
    while (line[i] && line[i] != 39) i++;
    if (line[i] != 39) return -1;  // unterminated string
    i++;
    t++;
    continue;
}
```

---

## 2. PARSING (parse.h)

### AST Node Definition (lines 23-25):
```c
#define NODE_QSVO       13   // shared variable offer (val = sym index, right = AP expr)
#define NODE_SVO_READ   14   // shared var indexed read (val = sym index, right = index expr)
#define NODE_SVO_WRITE  15   // shared var indexed write (val = sym index, left = index, right = value)
```

### Parsing qsvo Expression (lines 282-293):
The parser recognizes the dyadic form: `IDENT qsvo EXPR` or `'STRING' qsvo EXPR`

```c
// Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
    int sym_idx = node_val[left];
    parse_pos++;
    int right = parse_node(0);
    if (parse_err) return 0;
    int n = ast_new();
    node_type[n] = NODE_QSVO;
    node_val[n] = sym_idx;           // Which symbol (variable name)
    node_right[n] = right;           // The AP number expression
    return n;
}
```

### Parsing Indexed Access (lines 224-235):
For shared variable indexed read/write (`IDENT[expr]`):

```c
} else if (tok_type[parse_pos] == TOK_LBRAK) {
    // IDENT[expr] -- shared variable indexed read
    parse_pos++;
    int idx_expr = parse_node(0);
    if (parse_err) return 0;
    if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
    parse_pos++;
    int nd = ast_new();
    node_type[nd] = NODE_SVO_READ;
    node_val[nd] = sym_idx;
    node_right[nd] = idx_expr;
    left = nd;
}
```

### Indexed Write Parsing (lines 354-375):
```c
// Check for shared variable indexed write: IDENT[expr] <- expr
if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
    int sym_idx = sym_lookup(line, tok_val[0]);
    if (sym_idx < 0) { return -1; }
    parse_pos = 2;
    int idx_expr = parse_node(0);
    if (parse_err) return -1;
    if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
    parse_pos++;
    if (tok_type[parse_pos] == TOK_ASSIGN) {
        // IDENT[expr] <- expr (indexed write)
        parse_pos++;
        int val_expr = parse_node(0);
        if (parse_err) return -1;
        if (tok_type[parse_pos] != TOK_EOL) return -1;
        int n = ast_new();
        node_type[n] = NODE_SVO_WRITE;
        node_val[n] = sym_idx;
        node_left[n] = idx_expr;
        node_right[n] = val_expr;
        return n;
    }
}
```

---

## 3. SYMBOL TABLE MANAGEMENT (sym.h)

### Shared Variable Coupling Table (lines 19-21):
```c
// Shared variable table (□SVO coupling)
// svo_ap[i] = AP number for symbol i (0 = not shared)
int svo_ap[SYM_MAX];
```

Each symbol can be coupled to an auxiliary processor. When `qsvo` executes successfully, the AP number is stored here, enabling bracket indexing to route to MMIO instead of regular array access.

---

## 4. EVALUATION/EXECUTION (eval.h)

### NODE_QSVO Evaluation (lines 363-383):
This is the core of the qsvo implementation:

```c
if (ty == NODE_QSVO) {
    // Shared variable offer: IDENT qsvo AP
    // Evaluate AP number, couple symbol if AP supported
    int v = eval(node_right[n]);           // Evaluate AP expression
    if (eval_err) return -1;
    if (arr_rank(v) != 0) { eval_err = 4; return -1; }  // Must be scalar
    int ap = arr_get(v, 0);                // Extract AP number
    int sym_idx = node_val[n];

    if (ap == 242) {
        // AP 242: MMIO byte access (FF0000+offset)
        svo_ap[sym_idx] = 242;             // Store coupling
        int r = arr_scalar(2);             // Return coupling degree 2
        if (r < 0) { eval_err = 5; return -1; }
        return r;
    }

    // Unknown AP: return 0 (not coupled)
    svo_ap[sym_idx] = 0;
    int r = arr_scalar(0);                 // Return coupling degree 0
    if (r < 0) { eval_err = 5; return -1; }
    return r;
}
```

**Key Semantics:**
- Returns coupling degree (2 = coupled to AP 242, 0 = unknown AP, not coupled)
- Stores the AP number in `svo_ap[sym_idx]` for later indexed access
- Expression-usable: `RC <- 'MMIO' qsvo 242` assigns coupling degree to variable

### NODE_SVO_READ Evaluation (lines 385-419):
Handles both MMIO and regular vector indexing:

```c
if (ty == NODE_SVO_READ) {
    // Indexed read: IDENT[N]
    int sym_idx = node_val[n];
    int ap = svo_ap[sym_idx];              // Check if coupled

    if (ap != 0) {
        // Shared variable MMIO access
        int v = eval(node_right[n]);
        if (eval_err) return -1;
        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
        int offset = arr_get(v, 0);

        if (ap == 242) {
            int addr = 0xFF0000 + offset;  // MMIO address calculation
            int val = *(char *)addr;       // Hardware read
            val = val & 0xFF;
            int r = arr_scalar(val);
            if (r < 0) { eval_err = 5; return -1; }
            return r;
        }
        eval_err = 1;
        return -1;
    }

    // Regular vector bracket indexing: V[N]
    if (!sym_set_flag[sym_idx]) { eval_err = 2; return -1; }
    int arr = sym_val[sym_idx];
    int v = eval(node_right[n]);
    if (eval_err) return -1;
    if (arr_rank(v) != 0) { eval_err = 4; return -1; }
    int idx = arr_get(v, 0);
    int sz = arr_size(arr);
    if (idx < 0 || idx >= sz) { eval_err = 3; return -1; }  // LENGTH ERROR
    int val = arr_get(arr, idx);
    int r = arr_scalar(val);
    if (r < 0) { eval_err = 5; return -1; }
    return r;
}
```

### NODE_SVO_WRITE Evaluation (lines 421-458):
Handles MMIO writes and vector element updates:

```c
if (ty == NODE_SVO_WRITE) {
    // Indexed write: IDENT[N] <- expr
    int sym_idx = node_val[n];
    int ap = svo_ap[sym_idx];              // Check if coupled

    if (ap != 0) {
        // Shared variable MMIO write
        int idx = eval(node_left[n]);
        if (eval_err) return -1;
        if (arr_rank(idx) != 0) { eval_err = 4; return -1; }
        int offset = arr_get(idx, 0);
        int v = eval(node_right[n]);
        if (eval_err) return -1;
        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
        int val = arr_get(v, 0);

        if (ap == 242) {
            int addr = 0xFF0000 + offset;  // MMIO address calculation
            *(char *)addr = val & 0xFF;    // Hardware write
            return v;
        }
        eval_err = 1;
        return -1;
    }

    // Regular vector bracket indexed write: V[N] <- expr
    if (!sym_set_flag[sym_idx]) { eval_err = 2; return -1; }
    int arr = sym_val[sym_idx];
    int idxv = eval(node_left[n]);
    if (eval_err) return -1;
    if (arr_rank(idxv) != 0) { eval_err = 4; return -1; }
    int idx = arr_get(idxv, 0);
    int v = eval(node_right[n]);
    if (eval_err) return -1;
    if (arr_rank(v) != 0) { eval_err = 4; return -1; }
    int val = arr_get(v, 0);
    int sz = arr_size(arr);
    if (idx < 0 || idx >= sz) { eval_err = 3; return -1; }  // LENGTH ERROR
    arr_set(arr, idx, val);
    return v;
}
```

