44	// Allocate a new AST node
45	int ast_new() {
46	    if (node_count >= AST_MAX) {
47	        parse_err = 1;
48	        return 0;
49	    }
50	    int n = node_count;
51	    node_count++;
52	    node_left[n] = -1;
53	    node_right[n] = -1;
54	    return n;
55	}
