127	// Check if a reserved word can be used dyadically
128	int is_dyadic_res(int res_id) {
129	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR;
130	}
131	
132	// Temporary buffer for collecting strand elements
133	int strand_buf[64];
134	
135	int is_binop(int ty) {
136	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH ||
137	           ty == TOK_EQ || ty == TOK_NE || ty == TOK_LT || ty == TOK_GT ||
138	           ty == TOK_LE || ty == TOK_GE;
139	}
140	
141	// Check if token at pos could start an expression (for function call detection)
142	int can_start_expr(int pos) {
143	    int ty = tok_type[pos];
144	    if (ty == TOK_NUM || ty == TOK_LPAREN || ty == TOK_IDENT ||
145	        ty == TOK_MINUS || ty == TOK_RES || ty == TOK_QLED || ty == TOK_QSW) return 1;
146	    if (is_binop(ty) && tok_type[pos + 1] == TOK_SLASH) return 1;  // reduce
147	    return 0;
148	}
