150	// Combined parse function avoids mutual recursion.
151	// mode 0 = expression, mode 1 = value only
152	int parse_node(int mode);
153	
154	int parse_node(int mode) {
155	    if (parse_err) return 0;
156	
157	    int left;
158	    int ty = tok_type[parse_pos];
159	
160	    // -- Parse a value --
161	
162	    if (ty == TOK_NUM) {
163	        left = ast_num(tok_val[parse_pos]);
164	        parse_pos++;
165	
166	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
167	        if (tok_type[parse_pos] == TOK_NUM) {
168	            strand_buf[0] = node_val[left];
169	            int count = 1;
170	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
171	                strand_buf[count] = tok_val[parse_pos];
172	                parse_pos++;
173	                count++;
174	            }
175	            int aidx = arr_vector(count);
176	            if (aidx < 0) { parse_err = 1; return 0; }
177	            int si = 0;
178	            while (si < count) {
179	                arr_set(aidx, si, strand_buf[si]);
180	                si++;
181	            }
182	            left = ast_vec(aidx);
183	        }
184	    } else if (ty == TOK_LPAREN) {
185	        parse_pos++;
186	        left = parse_node(0);
187	        if (parse_err) return 0;
188	        if (tok_type[parse_pos] != TOK_RPAREN) {
189	            parse_err = 1;
190	            return 0;
191	        }
192	        parse_pos++;
193	    } else if (ty == TOK_QLED) {
194	        int n = ast_new();
195	        node_type[n] = NODE_QLED;
196	        left = n;
197	        parse_pos++;
198	    } else if (ty == TOK_QSW) {
199	        int n = ast_new();
200	        node_type[n] = NODE_QSW;
201	        left = n;
202	        parse_pos++;
203	    } else if (ty == TOK_STRING) {
204	        // String literal becomes an identifier (for 'NAME' qsvo AP)
205	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
206	        if (sym_idx < 0) { parse_err = 1; return 0; }
207	        left = ast_ident(sym_idx);
208	        parse_pos++;
209	    } else if (ty == TOK_IDENT) {
210	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
211	        if (sym_idx < 0) { parse_err = 1; return 0; }
212	        parse_pos++;
213	        // Check for monadic function call
214	        int fi = fn_lookup(sym_idx);
215	        if (fi >= 0 && fn_left_sym[fi] < 0 && can_start_expr(parse_pos)) {
216	            // Monadic user function call: FN expr
217	            int arg = parse_node(0);
218	            if (parse_err) return 0;
219	            int nd = ast_new();
220	            node_type[nd] = NODE_FNCALL;
221	            node_val[nd] = fi;
222	            node_right[nd] = arg;
223	            left = nd;
224	        } else if (tok_type[parse_pos] == TOK_LBRAK) {
225	            // IDENT[expr] -- shared variable indexed read
226	            parse_pos++;
227	            int idx_expr = parse_node(0);
228	            if (parse_err) return 0;
229	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
230	            parse_pos++;
231	            int nd = ast_new();
232	            node_type[nd] = NODE_SVO_READ;
233	            node_val[nd] = sym_idx;
234	            node_right[nd] = idx_expr;
235	            left = nd;
236	        } else {
237	            left = ast_ident(sym_idx);
238	        }
239	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
240	        // Reduce operator: +/ -/ */ (op followed by slash)
241	        int op = ty;
242	        parse_pos = parse_pos + 2;
243	        int operand = parse_node(0);
244	        if (parse_err) return 0;
245	        left = ast_reduce(op, operand);
246	    } else if (ty == TOK_RES) {
247	        // Monadic primitive function (e.g. iota expr)
248	        int res_id = tok_val[parse_pos];
249	        parse_pos++;
250	        int operand = parse_node(0);
251	        if (parse_err) return 0;
252	        left = ast_monad(res_id, operand);
253	    } else if (ty == TOK_MINUS) {
254	        // Monadic negate: applies to entire right expression (APL rule)
255	        parse_pos++;
256	        int operand = parse_node(0);
257	        if (parse_err) return 0;
258	        left = ast_neg(operand);
259	    } else {
260	        parse_err = 1;
261	        return 0;
262	    }
263	
264	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
265	
266	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
267	        int op = tok_type[parse_pos];
268	        parse_pos++;
269	        int right = parse_node(0);
270	        if (parse_err) return 0;
271	        return ast_binop(op, left, right);
272	    }
273	
274	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
275	        int res_id = tok_val[parse_pos];
276	        parse_pos++;
277	        int right = parse_node(0);
278	        if (parse_err) return 0;
279	        return ast_dyad(res_id, left, right);
280	    }
281	
282	    // Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
283	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
284	        int sym_idx = node_val[left];
285	        parse_pos++;
286	        int right = parse_node(0);
287	        if (parse_err) return 0;
288	        int n = ast_new();
289	        node_type[n] = NODE_QSVO;
290	        node_val[n] = sym_idx;
291	        node_right[n] = right;
292	        return n;
293	    }
294	
295	    // Dyadic user function call: expr FN expr
296	    if (mode == 0 && tok_type[parse_pos] == TOK_IDENT) {
297	        int dsym = sym_lookup(parse_line, tok_val[parse_pos]);
298	        if (dsym >= 0) {
299	            int dfi = fn_lookup(dsym);
300	            if (dfi >= 0 && fn_left_sym[dfi] >= 0) {
301	                parse_pos++;
302	                int right = parse_node(0);
303	                if (parse_err) return 0;
304	                int nd = ast_new();
305	                node_type[nd] = NODE_FNCALL;
306	                node_val[nd] = dfi;
307	                node_left[nd] = left;
308	                node_right[nd] = right;
309	                return nd;
310	            }
311	        }
312	    }
313	
314	    return left;
315	}
