317	// Parse the token stream. Returns root node index, or -1 on error.
318	// line is needed for identifier name resolution into the symbol table.
319	int parse(char *line) {
320	    node_count = 0;
321	    parse_pos = 0;
322	    parse_err = 0;
323	    parse_line = line;
324	
325	    // Check for qled assignment: qled <- expr
326	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
327	        parse_pos = 2;
328	        int expr = parse_node(0);
329	        if (parse_err) return -1;
330	        if (tok_type[parse_pos] != TOK_EOL) return -1;
331	        int n = ast_new();
332	        node_type[n] = NODE_QLED_ASSIGN;
333	        node_right[n] = expr;
334	        return n;
335	    }
336	
337	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
338	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
339	        return -1;
340	    }
341	
342	    // Check for quad output: [] <- expr (IBM 5100 convention)
343	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
344	        parse_pos = 2;
345	        int expr = parse_node(0);
346	        if (parse_err) return -1;
347	        if (tok_type[parse_pos] != TOK_EOL) return -1;
348	        int n = ast_new();
349	        node_type[n] = NODE_QOUT;
350	        node_right[n] = expr;
351	        return n;
352	    }
353	
354	    // Check for shared variable indexed write: IDENT[expr] <- expr
355	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
356	        int sym_idx = sym_lookup(line, tok_val[0]);
357	        if (sym_idx < 0) { return -1; }
358	        parse_pos = 2;
359	        int idx_expr = parse_node(0);
360	        if (parse_err) return -1;
361	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
362	        parse_pos++;
363	        if (tok_type[parse_pos] == TOK_ASSIGN) {
364	            // IDENT[expr] <- expr (indexed write)
365	            parse_pos++;
366	            int val_expr = parse_node(0);
367	            if (parse_err) return -1;
368	            if (tok_type[parse_pos] != TOK_EOL) return -1;
369	            int n = ast_new();
370	            node_type[n] = NODE_SVO_WRITE;
371	            node_val[n] = sym_idx;
372	            node_left[n] = idx_expr;
373	            node_right[n] = val_expr;
374	            return n;
375	        }
376	        if (tok_type[parse_pos] != TOK_EOL) {
377	            // IDENT[expr] followed by more (could be in expression context)
378	            // For now, only standalone read supported at top level
379	            // Fall through to expression parsing below
380	            parse_pos = 0;
381	            node_count = 0;
382	            parse_err = 0;
383	        } else {
384	            // IDENT[expr] standalone read
385	            int n = ast_new();
386	            node_type[n] = NODE_SVO_READ;
387	            node_val[n] = sym_idx;
388	            node_right[n] = idx_expr;
389	            return n;
390	        }
391	    }
392	
393	    // Check for goto: goto expr  or  goto (expr)/LABEL
394	    if (tok_type[0] == TOK_GOTO) {
395	        parse_pos = 1;
396	        if (tok_type[1] == TOK_LPAREN) {
397	            // Conditional: goto (expr)/TARGET
398	            parse_pos = 2;
399	            int cond = parse_node(0);
400	            if (parse_err) return -1;
401	            if (tok_type[parse_pos] != TOK_RPAREN) return -1;
402	            parse_pos++;
403	            if (tok_type[parse_pos] != TOK_SLASH) return -1;
404	            parse_pos++;
405	            int target = parse_node(0);
406	            if (parse_err) return -1;
407	            if (tok_type[parse_pos] != TOK_EOL) return -1;
408	            int n = ast_new();
409	            node_type[n] = NODE_CGOTO;
410	            node_left[n] = cond;
411	            node_right[n] = target;
412	            return n;
413	        }
414	        // Unconditional: goto expr
415	        int target = parse_node(0);
416	        if (parse_err) return -1;
417	        if (tok_type[parse_pos] != TOK_EOL) return -1;
418	        int n = ast_new();
419	        node_type[n] = NODE_GOTO;
420	        node_right[n] = target;
421	        return n;
422	    }
423	
424	    // Check for assignment: IDENT <- expr
425	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
426	        int sym_idx = sym_lookup(line, tok_val[0]);
427	        if (sym_idx < 0) { return -1; }
428	        parse_pos = 2;
429	        int expr = parse_node(0);
430	        if (parse_err) return -1;
431	        if (tok_type[parse_pos] != TOK_EOL) return -1;
432	        return ast_assign(sym_idx, expr);
433	    }
434	
435	    int root = parse_node(0);
436	
437	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
438	        parse_err = 1;
439	    }
440	
441	    if (parse_err) return -1;
442	    return root;
443	}
444	
445	// Debug: dump AST with full parenthesization
446	void ast_dump(int n) {
447	    if (n < 0 || n >= node_count) return;
448	
449	    int ty = node_type[n];
450	    if (ty == NODE_NUM) {
451	        print_int(node_val[n]);
452	    } else if (ty == NODE_BINOP) {
453	        putchar(40);
454	        ast_dump(node_left[n]);
455	        putchar(32);
456	        if (node_val[n] == TOK_PLUS)  putchar(43);
457	        if (node_val[n] == TOK_MINUS) putchar(45);
458	        if (node_val[n] == TOK_STAR)  putchar(42);
459	        if (node_val[n] == TOK_SLASH) putchar(47);
460	        putchar(32);
461	        ast_dump(node_right[n]);
462	        putchar(41);
463	    } else if (ty == NODE_NEG) {
464	        putchar(40);
465	        putchar(45);
466	        ast_dump(node_right[n]);
467	        putchar(41);
468	    }
469	}
